import React, { useState, useEffect } from 'react';
import API from '../api/axios';
import Navigation from '../components/Navigation';

const ComplaintsList = () => {
    const [complaints, setComplaints] = useState([]);
    const [loading, setLoading] = useState(true);
    const [selectedComplaint, setSelectedComplaint] = useState(null);
    const [userRole, setUserRole] = useState('');
    const [users, setUsers] = useState([]);
    const [filters, setFilters] = useState({ status: '', type: '' });
    const [message, setMessage] = useState('');

    const statusOptions = ['Pending', 'Assigned', 'In-Progress', 'On-Hold', 'Completed'];
    const typeOptions = ['PC Hardware', 'PC Software', 'Application Issues', 'Network', 'Electronics', 'Plumbing'];

    useEffect(() => {
        const role = localStorage.getItem('role');
        setUserRole(role);
        fetchComplaints();
        if (role === 'SuperAdmin') {
            fetchUsers();
        }
    }, []);

    const fetchComplaints = async () => {
        try {
            const { data } = await API.get('/complaints');
            setComplaints(data);
        } catch (err) {
            setMessage({ type: 'error', text: 'Error fetching complaints' });
        } finally {
            setLoading(false);
        }
    };

    const fetchUsers = async () => {
        try {
            const { data } = await API.get('/master/users');
            setUsers(data.filter(u => ['Plumber', 'Electrician', 'Networking Staff', 'Software Developer'].includes(u.role)));
        } catch (err) {
            console.error('Error fetching users:', err);
        }
    };

    const handleAssign = async (complaintId, assigneeId) => {
        try {
            await API.put(`/complaints/${complaintId}/assign`, { assignedTo: assigneeId });
            fetchComplaints();
            setSelectedComplaint(null);
            setMessage({ type: 'success', text: '✓ Complaint assigned successfully!' });
            setTimeout(() => setMessage(''), 3000);
        } catch (err) {
            setMessage({ type: 'error', text: 'Error assigning complaint' });
        }
    };

    const handleStatusChange = async (complaintId, newStatus) => {
        try {
            await API.put(`/complaints/${complaintId}/status`, { status: newStatus });
            fetchComplaints();
            setSelectedComplaint(null);
            setMessage({ type: 'success', text: '✓ Status updated successfully!' });
            setTimeout(() => setMessage(''), 3000);
        } catch (err) {
            setMessage({ type: 'error', text: 'Error updating status' });
        }
    };

    const isSuperAdmin = userRole === 'SuperAdmin';
    const isStaff = ['Plumber', 'Electrician', 'Networking Staff', 'Software Developer'].includes(userRole);

    const filteredComplaints = complaints.filter(c => {
        if (filters.status && c.status !== filters.status) return false;
        if (filters.type && c.complaintType !== filters.type) return false;
        return true;
    });

    if (loading) return (
        <div style={styles.pageWrapper}>
            <Navigation />
            <div style={{ ...styles.contentArea, textAlign: 'center', paddingTop: '100px' }}>
                <div style={styles.spinner}>⏳</div>
            </div>
        </div>
    );

    return (
        <div style={styles.pageWrapper}>
            <Navigation />
            <div style={styles.contentArea}>
                <div style={styles.headerSection}>
                    <h1 style={styles.mainTitle}>📋 All Tickets</h1>
                    <p style={styles.subtitle}>View and manage all support tickets</p>
                </div>

                {message && (
                    <div style={{
                        ...styles.alertBox,
                        background: message.type === 'success'
                            ? 'rgba(16, 185, 129, 0.2)'
                            : 'rgba(239, 68, 68, 0.2)',
                        borderColor: message.type === 'success' ? '#10b981' : '#ef4444',
                        color: message.type === 'success' ? '#a7f3d0' : '#fca5a5',
                    }}>
                        {message.text}
                    </div>
                )}

                {/* Filters */}
                <div style={styles.filtersBox}>
                    <div style={styles.filterGroup}>
                        <label style={styles.filterLabel}>🔍 Filter by Status</label>
                        <select
                            value={filters.status}
                            onChange={e => setFilters({ ...filters, status: e.target.value })}
                            style={styles.filterSelect}
                        >
                            <option value="">All Status</option>
                            {statusOptions.map(s => <option key={s} value={s}>{s}</option>)}
                        </select>
                    </div>
                    <div style={styles.filterGroup}>
                        <label style={styles.filterLabel}>🏷️ Filter by Type</label>
                        <select
                            value={filters.type}
                            onChange={e => setFilters({ ...filters, type: e.target.value })}
                            style={styles.filterSelect}
                        >
                            <option value="">All Types</option>
                            {typeOptions.map(t => <option key={t} value={t}>{t}</option>)}
                        </select>
                    </div>
                </div>

                {/* Complaints Table */}
                <div style={styles.tableCard}>
                    <div style={styles.tableContainer}>
                        <table style={styles.table}>
                            <thead>
                                <tr style={styles.tableHeaderRow}>
                                    <th style={{ ...styles.tableHeader, width: '8%' }}>ID</th>
                                    <th style={{ ...styles.tableHeader, width: '9%' }}>Block</th>
                                    <th style={{ ...styles.tableHeader, width: '7%' }}>Room</th>
                                    <th style={{ ...styles.tableHeader, width: '11%' }}>Type</th>
                                    <th style={{ ...styles.tableHeader, width: '10%' }}>Status</th>
                                    <th style={{ ...styles.tableHeader, width: '10%' }}>Raised By</th>
                                    <th style={{ ...styles.tableHeader, width: '12%' }}>Assigned To</th>
                                    {isSuperAdmin && <th style={{ ...styles.tableHeader, width: '18%' }}>Assign Staff</th>}
                                    {(isSuperAdmin || isStaff) && <th style={{ ...styles.tableHeader, width: '15%' }}>Update Status</th>}
                                    <th style={{ ...styles.tableHeader, width: '7%' }}>View</th>
                                </tr>
                            </thead>
                            <tbody>
                                {filteredComplaints.length === 0 ? (
                                    <tr>
                                        <td colSpan="10" style={{ ...styles.tableCell, textAlign: 'center', color: '#94a3b8', padding: '30px' }}>
                                            No tickets found
                                        </td>
                                    </tr>
                                ) : (
                                    filteredComplaints.map((complaint, idx) => (
                                        <tr key={complaint._id} style={idx % 2 === 0 ? styles.tableRowEven : styles.tableRowOdd}>
                                            <td style={styles.tableCell}>
                                                <span style={styles.idBadge}>{complaint._id.substring(0, 8)}</span>
                                            </td>
                                            <td style={styles.tableCell}>{complaint.blockName}</td>
                                            <td style={styles.tableCell}>{complaint.roomNumber}</td>
                                            <td style={styles.tableCell}>{complaint.complaintType}</td>
                                            <td style={styles.tableCell}>
                                                <span style={{ ...styles.statusBadge, background: getStatusColor(complaint.status) }}>
                                                    {complaint.status}
                                                </span>
                                            </td>
                                            <td style={styles.tableCell}>{complaint.user?.userName}</td>
                                            <td style={styles.tableCell}>
                                                {complaint.assignedTo?.userName || <span style={{ color: '#ef4444' }}>❌ Unassigned</span>}
                                            </td>
                                            {isSuperAdmin && (
                                                <td style={styles.tableCell}>
                                                    <select
                                                        value={complaint.assignedTo?._id || ''}
                                                        onChange={e => handleAssign(complaint._id, e.target.value)}
                                                        style={styles.inlineSelect}
                                                    >
                                                        <option value="">-- Assign --</option>
                                                        {users.map(u => <option key={u._id} value={u._id}>{u.userName} ({u.role})</option>)}
                                                    </select>
                                                </td>
                                            )}
                                            {(isSuperAdmin || isStaff) && (
                                                <td style={styles.tableCell}>
                                                    <select
                                                        value={complaint.status}
                                                        onChange={e => handleStatusChange(complaint._id, e.target.value)}
                                                        style={styles.inlineSelect}
                                                    >
                                                        {statusOptions.map(s => <option key={s} value={s}>{s}</option>)}
                                                    </select>
                                                </td>
                                            )}
                                            <td style={styles.tableCell}>
                                                <button
                                                    onClick={() => setSelectedComplaint(complaint)}
                                                    style={styles.viewBtn}
                                                >
                                                    👁️
                                                </button>
                                            </td>
                                        </tr>
                                    ))
                                )}
                            </tbody>
                        </table>
                    </div>
                </div>
            </div>

            {/* Detail Modal */}
            {selectedComplaint && (
                <div style={styles.modalOverlay}>
                    <div style={styles.modal}>
                        <div style={styles.modalHeader}>
                            <h2 style={styles.modalTitle}>🎫 Ticket Details</h2>
                            <button
                                onClick={() => setSelectedComplaint(null)}
                                style={styles.closeBtn}
                            >
                                ✕
                            </button>
                        </div>

                        <div style={styles.modalBody}>
                            <div style={styles.detailRow}>
                                <label style={styles.detailLabel}>Block</label>
                                <p style={styles.detailValue}>{selectedComplaint.blockName}</p>
                            </div>
                            <div style={styles.detailRow}>
                                <label style={styles.detailLabel}>Room</label>
                                <p style={styles.detailValue}>{selectedComplaint.roomNumber}</p>
                            </div>
                            <div style={styles.detailRow}>
                                <label style={styles.detailLabel}>Type</label>
                                <p style={styles.detailValue}>{selectedComplaint.complaintType}</p>
                            </div>
                            <div style={styles.detailRow}>
                                <label style={styles.detailLabel}>Remarks</label>
                                <p style={styles.detailValue}>{selectedComplaint.complaintRemarks}</p>
                            </div>
                            <div style={styles.detailRow}>
                                <label style={styles.detailLabel}>Raised By</label>
                                <p style={styles.detailValue}>
                                    {selectedComplaint.user?.userName}
                                    <br />
                                    <span style={{ fontSize: '0.85rem', color: '#94a3b8' }}>{selectedComplaint.user?.email}</span>
                                </p>
                            </div>

                            {/* Super Admin - Assign */}
                            {isSuperAdmin && (
                                <div style={styles.detailRow}>
                                    <label style={styles.detailLabel}>Assign To</label>
                                    <select
                                        onChange={e => handleAssign(selectedComplaint._id, e.target.value)}
                                        style={styles.detailSelect}
                                    >
                                        <option value="">Select Staff Member</option>
                                        {users.map(u => <option key={u._id} value={u._id}>{u.userName} ({u.role})</option>)}
                                    </select>
                                </div>
                            )}

                            {/* Status Change */}
                            {(isSuperAdmin || (isStaff && selectedComplaint.assignedTo?._id === localStorage.getItem('userId'))) && (
                                <div style={styles.detailRow}>
                                    <label style={styles.detailLabel}>Update Status</label>
                                    <select
                                        value={selectedComplaint.status}
                                        onChange={e => handleStatusChange(selectedComplaint._id, e.target.value)}
                                        style={styles.detailSelect}
                                    >
                                        {statusOptions.map(s => <option key={s} value={s}>{s}</option>)}
                                    </select>
                                </div>
                            )}
                        </div>

                        <div style={styles.modalFooter}>
                            <button
                                onClick={() => setSelectedComplaint(null)}
                                style={styles.closeModalBtn}
                            >
                                Close
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

const getStatusColor = (status) => {
    const colors = {
        'Pending': 'linear-gradient(135deg, #f59e0b, #f97316)',
        'Assigned': 'linear-gradient(135deg, #8b5cf6, #a78bfa)',
        'In-Progress': 'linear-gradient(135deg, #3b82f6, #60a5fa)',
        'On-Hold': 'linear-gradient(135deg, #ef4444, #f87171)',
        'Completed': 'linear-gradient(135deg, #10b981, #34d399)'
    };
    return colors[status] || 'linear-gradient(135deg, #6b7280, #9ca3af)';
};

const styles = {
    pageWrapper: {
        minHeight: '100vh',
        background: 'linear-gradient(135deg, #0f172a 0%, #1a1f35 50%, #0f172a 100%)',
        color: '#e0e7ff',
        fontFamily: "'Poppins', sans-serif",
    },
    contentArea: {
        maxWidth: '1400px',
        margin: '0 auto',
        padding: '40px 30px',
    },
    headerSection: {
        marginBottom: '40px',
    },
    mainTitle: {
        fontSize: '2.2rem',
        fontWeight: 800,
        background: 'linear-gradient(135deg, #38bdf8, #818cf8)',
        WebkitBackgroundClip: 'text',
        WebkitTextFillColor: 'transparent',
        backgroundClip: 'text',
        marginBottom: '10px',
    },
    subtitle: {
        fontSize: '1rem',
        color: '#94a3b8',
        fontWeight: 500,
    },
